38	#define DEFAULT_UART_BAUD 921600
39	#define RAMDISK_BASE 0x4000000
40	#define BLOCK_SIZE 1024
41	#define PROGRESS_BAR_WIDTH 40
42	#define MIN_SEGMENT_ALLOC 1024
