51	int open_serial_port(const char *path)
52	{
53	    struct termios serialopts;
54	    int serial_fd;
55	
56	    serial_fd = open(path, O_RDWR | O_NOCTTY);
57	    if (serial_fd < 0)
58	    {
59	        perror("couldn't open serial port");
60	        return -1;
61	    }
62	
63	    // Configure serial options
64	    memset(&serialopts, 0, sizeof(serialopts));
65	    serialopts.c_cflag = CS8 | CLOCAL | CREAD;
66	    cfsetspeed(&serialopts, DEFAULT_UART_BAUD);
67	    if (tcsetattr(serial_fd, TCSANOW, &serialopts) != 0)
68	    {
69	        perror("Unable to initialize serial port");
70	        return -1;
71	    }
72	
73	    // Clear out any junk that may already be buffered in the
74	    // serial driver (otherwise the ping sequence may fail)
75	    tcflush(serial_fd, TCIOFLUSH);
76	
77	    return serial_fd;
78	}
