80	// Returns true if the byte was read successfully, false if a timeout
81	// or other error occurred.
82	bool read_serial_byte(int serial_fd, unsigned char *ch, int timeout_ms)
83	{
84	    fd_set set;
85	    struct timeval tv;
86	    int ready_fds;
87	
88	    FD_ZERO(&set);
89	    FD_SET(serial_fd, &set);
90	
91	    tv.tv_sec = timeout_ms / 1000;
92	    tv.tv_usec = (timeout_ms % 1000) * 1000;
93	
94	    do
95	    {
96	        ready_fds = select(FD_SETSIZE, &set, NULL, NULL, &tv);
97	    }
98	    while (ready_fds < 0 && errno == EINTR);
99	
100	    if (ready_fds == 0)
101	        return false;
102	
103	    if (read(serial_fd, ch, 1) != 1)
104	    {
105	        perror("read");
106	        return false;
107	    }
108	
109	    return true;
110	}
