112	bool read_serial_long(int serial_fd, unsigned int *out, int timeout)
113	{
114	    unsigned int result = 0;
115	    unsigned char ch;
116	    int i;
117	
118	    for (i = 0; i < 4; i++)
119	    {
120	        if (!read_serial_byte(serial_fd, &ch, timeout))
121	            return false;
122	
123	        result = (result >> 8) | ((unsigned int) ch << 24);
124	    }
125	
126	    *out = result;
127	    return true;
128	}
