130	bool write_serial_byte(int serial_fd, unsigned int ch)
131	{
132	    if (write(serial_fd, &ch, 1) != 1)
133	    {
134	        perror("write");
135	        return false;
136	    }
137	
138	    return true;
139	}
140	
141	bool write_serial_long(int serial_fd, unsigned int value)
142	{
143	    unsigned char out[4] =
144	    {
145	        value & 0xff,
146	        (value >> 8) & 0xff,
147	        (value >> 16) & 0xff,
148	        (value >> 24) & 0xff
149	    };
150	
151	    if (write(serial_fd, out, 4) != 4)
152	    {
153	        perror("write");
154	        return false;
155	    }
156	
157	    return true;
158	}
