160	bool load_memory(int serial_fd, unsigned int address, const unsigned char *buffer, unsigned int length)
161	{
162	    unsigned int target_checksum;
163	    unsigned int local_checksum;
164	    unsigned char ch;
165	    unsigned int i;
166	
167	    if (!write_serial_byte(serial_fd, LOAD_MEMORY_REQ))
168	        return false;
169	
170	    if (!write_serial_long(serial_fd, address))
171	        return false;
172	
173	    if (!write_serial_long(serial_fd, length))
174	        return false;
175	
176	    if (write(serial_fd, buffer, length) != length)
177	    {
178	        fprintf(stderr, "\nError writing to serial port\n");
179	        return false;
180	    }
181	
182	    // wait for ack
183	    if (!read_serial_byte(serial_fd, &ch, 15000))
184	    {
185	        fprintf(stderr, "\n%08x Did not get ack for load memory\n", address);
186	        return false;
187	    }
188	    else if (ch != LOAD_MEMORY_ACK)
189	    {
190	        fprintf(stderr, "\n%08x Did not get ack for load memory, got %02x instead\n", address, ch);
191	        return false;
192	    }
193	
194	    // Compute FNV-1a hash
195	    local_checksum = 2166136261;
196	    for (i = 0; i < length; i++)
197	        local_checksum = (local_checksum ^ buffer[i]) * 16777619;
198	
199	    if (!read_serial_long(serial_fd, &target_checksum, 5000))
200	    {
201	        fprintf(stderr, "\n%08x timed out reading checksum\n", address);
202	        return false;
203	    }
204	
205	    if (target_checksum != local_checksum)
206	    {
207	        fprintf(stderr, "\n%08x checksum mismatch want %08x got %08x\n",
208	                address, local_checksum, target_checksum);
209	        return false;
210	    }
211	
212	    return true;
213	}
