215	bool clear_memory(int serial_fd, unsigned int address, unsigned int length)
216	{
217	    unsigned char ch;
218	
219	    if (!write_serial_byte(serial_fd, CLEAR_MEMORY_REQ))
220	        return false;
221	
222	    if (!write_serial_long(serial_fd, address))
223	        return false;
224	
225	    if (!write_serial_long(serial_fd, length))
226	        return false;
227	
228	    // wait for ack
229	    if (!read_serial_byte(serial_fd, &ch, 15000) || ch != CLEAR_MEMORY_ACK)
230	    {
231	        fprintf(stderr, "\n%08x Did not get ack for clear memory\n", address);
232	        return false;
233	    }
234	
235	    return true;
236	}
