238	bool ping_target(int serial_fd)
239	{
240	    int retry;
241	    unsigned char ch;
242	
243	    printf("ping target");
244	
245	    int target_ready = 0;
246	    for (retry = 0; retry < 20; retry++)
247	    {
248	        printf(".");
249	        fflush(stdout);
250	        write_serial_byte(serial_fd, PING_REQ);
251	        if (read_serial_byte(serial_fd, &ch, 250) && ch == PING_ACK)
252	        {
253	            target_ready = 1;
254	            break;
255	        }
256	    }
257	
258	    if (!target_ready)
259	    {
260	        fprintf(stderr, "target is not responding\n");
261	        return false;
262	    }
263	
264	    printf("\n");
265	
266	    return true;
267	}
