269	// An error has occurred. Resynchronize so we can retry the command.
270	bool fix_connection(int serial_fd)
271	{
272	    unsigned char ch = 0;
273	    int chars_read = 0;
274	    bool ping_seen = false;
275	    int retry = 0;
276	
277	    // Clear out any waiting BAD_COMMAND bytes
278	    // May grab an extra byte
279	    while (read_serial_byte(serial_fd, &ch, 250) && ch == BAD_COMMAND)
280	        chars_read++;
281	
282	    printf("%d BAD_COMMAND bytes seen, last was %02x\n", chars_read, ch);
283	
284	    // Send pings until the processor responds
285	    // This can help if the processor is expecting data from us
286	    while (1)
287	    {
288	        if (read_serial_byte(serial_fd, &ch, 25))
289	        {
290	            if (ping_seen)
291	                continue; // Once you've seen one ping, ignore the rest
292	            else if (ch == PING_ACK)
293	            {
294	                printf("Ping return seen.\n");
295	                ping_seen = true;
296	            }
297	            else
298	                printf("byte read: %02x\n", ch);
299	        }
300	        else
301	        {
302	            // If there's no more data, and we've seen one ping,
303	            // we're done here.
304	            if (ping_seen)
305	                return true;
306	        }
307	
308	        if (!ping_seen)
309	        {
310	            retry++;
311	            if (!write_serial_byte(serial_fd, PING_REQ))
312	                return false;
313	        }
314	
315	        if (retry > 40)
316	        {
317	            printf("Cannot fix connection, no ping from board received.\n");
318	            printf("Try resetting the board (KEY0) and rerunning.\n");
319	            return false;
320	        }
321	    }
322	}
