324	bool send_execute_command(int serial_fd)
325	{
326	    unsigned char ch;
327	
328	    write_serial_byte(serial_fd, EXECUTE_REQ);
329	    if (!read_serial_byte(serial_fd, &ch, 15000) || ch != EXECUTE_ACK)
330	    {
331	        fprintf(stderr, "Target returned invalid response starting execution\n");
332	        return false;
333	    }
334	
335	    return true;
336	}
