338	void do_console_mode(int serial_fd)
339	{
340	    fd_set set;
341	    int ready_fds;
342	    char read_buffer[256];
343	    ssize_t got;
344	    int i;
345	    int done = 0;
346	
347	    while (!done)
348	    {
349	        FD_ZERO(&set);
350	        FD_SET(serial_fd, &set);
351	        FD_SET(STDIN_FILENO, &set);	// stdin
352	
353	        do
354	        {
355	            ready_fds = select(FD_SETSIZE, &set, NULL, NULL, NULL);
356	        }
357	        while (ready_fds < 0 && errno == EINTR);
358	
359	        if (FD_ISSET(serial_fd, &set))
360	        {
361	            // Serial -> Terminal
362	            got = read(serial_fd, read_buffer, sizeof(read_buffer));
363	            if (got <= 0)
364	            {
365	                perror("read");
366	                return;
367	            }
368	
369	            // A ^D will terminate the exit console mode.
370	            for (i = 0; i < got; i++)
371	                if (read_buffer[i] == 4)
372	                    done = 1;
373	
374	            if (write(STDOUT_FILENO, read_buffer, (unsigned int) got) < got)
375	            {
376	                perror("write");
377	                return;
378	            }
379	        }
380	
381	        if (FD_ISSET(STDIN_FILENO, &set))
382	        {
383	            // Terminal -> Serial
384	            got = read(STDIN_FILENO, read_buffer, sizeof(read_buffer));
385	            if (got <= 0)
386	            {
387	                perror("read");
388	                return;
389	            }
390	
391	            if (write(serial_fd, read_buffer, (unsigned int) got) != got)
392	            {
393	                perror("write");
394	                return;
395	            }
396	        }
397	    }
398	}
