400	void append_to_segment(struct segment *seg, unsigned int value)
401	{
402	    if (seg->length == 0 || seg->length == MIN_SEGMENT_ALLOC
403	        || (seg->length & (seg->length - 1)) == 0) {
404	        int new_size = seg->length < MIN_SEGMENT_ALLOC ? MIN_SEGMENT_ALLOC : seg->length * 2;
405	        seg->data = (unsigned char*) realloc(seg->data, new_size);
406	    }
407	
408	    seg->data[seg->length++] = value >> 24;
409	    seg->data[seg->length++] = (value >> 16) & 0xff;
410	    seg->data[seg->length++] = (value >> 8) & 0xff;
411	    seg->data[seg->length++] = value & 0xff;
412	}
