414	inline uint32_t hex_digit_val(char ch) {
415	    if (ch >= '0' && ch <= '9')
416	        return (uint32_t) (ch - '0');
417	    else if (ch >= 'a' && ch <= 'f')
418	        return (uint32_t) (ch - 'a' + 10);
419	    else if (ch >= 'A' && ch <= 'F')
420	        return (uint32_t) (ch - 'A' + 10);
421	    else
422	        return UINT32_MAX;
423	}
