425	//
426	// Format is defined in IEEE 1364-2001, section 17.2.8
427	//
428	struct segment *read_hex_file(const char *filename)
429	{
430	    FILE *file;
431	    int line_num = 1;
432	    uint32_t number_value;
433	    int push_back_char = -1;
434	    bool done = false;
435	    struct segment *segments;
436	    struct segment *current_segment;
437	
438	    enum
439	    {
440	        SCAN_SPACE,
441	        SCAN_SLASH,
442	        SCAN_ADDRESS,
443	        SCAN_NUMBER,
444	        SCAN_MULTI_LINE_COMMENT,
445	        SCAN_ASTERISK,
446	        SCAN_SINGLE_LINE_COMMENT
447	    } state = SCAN_SPACE;
448	
449	    file = fopen(filename, "r");
450	    if (file == NULL)
451	    {
452	        perror("read_hex_file: error opening hex file");
453	        return NULL;
454	    }
455	
456	    segments = current_segment = (struct segment*) calloc(sizeof(struct segment), 1);
457	
458	    while (!done) {
459	        int ch;
460	        if (push_back_char != -1)
461	        {
462	            ch = push_back_char;
463	            push_back_char = -1;
464	        }
465	        else
466	            ch = fgetc(file);
467	
468	        switch (state)
469	        {
470	            case SCAN_SPACE:
471	                if (ch == EOF)
472	                    done = true;
473	                else if (ch == '/')
474	                    state = SCAN_SLASH;
475	                else if (ch == '@')
476	                {
477	                    state = SCAN_ADDRESS;
478	                    number_value = 0;
479	                }
480	                else if (isxdigit(ch))
481	                {
482	                    number_value = hex_digit_val(ch);
483	                    state = SCAN_NUMBER;
484	                }
485	                else if (!isspace(ch))
486	                {
487	                    fprintf(stderr, "read_hex_file: Invalid character %c in line %d\n", ch, line_num);
488	                    fclose(file);
489	                    return NULL;
490	                } else if (ch == '\n')
491	                    line_num++;
492	
493	                break;
494	
495	            case SCAN_SLASH:
496	                if (ch == '*')
497	                    state = SCAN_MULTI_LINE_COMMENT;
498	                else if (ch == '/')
499	                    state = SCAN_SINGLE_LINE_COMMENT;
500	                else
501	                {
502	                    fprintf(stderr, "read_hex_file: Invalid character %c in line %d\n", ch, line_num);
503	                    fclose(file);
504	                    return NULL;
505	                }
506	
507	                break;
508	
509	            case SCAN_SINGLE_LINE_COMMENT:
510	                if (ch == '\n') {
511	                    state = SCAN_SPACE;
512	                } else if (ch == EOF) {
513	                    done = true;
514	                }
515	
516	                break;
517	
518	            case SCAN_MULTI_LINE_COMMENT:
519	                if (ch == '*')
520	                    state = SCAN_ASTERISK;
521	                else if (ch == EOF)
522	                {
523	                    fprintf(stderr, "read_hex_file: Missing */ at end of file\n");
524	                    fclose(file);
525	                    return NULL;
526	                }
527	
528	                break;
529	
530	            case SCAN_ASTERISK:
531	                if (ch == '/')
532	                    state = SCAN_SPACE;
533	                else if (ch == EOF)
534	                {
535	                    fprintf(stderr, "read_hex_file: Missing */ at end of file\n");
536	                    fclose(file);
537	                    return NULL;
538	                }
539	
540	                break;
541	
542	            case SCAN_NUMBER:
543	                if (isxdigit(ch))
544	                {
545	                    if ((number_value & 0xf0000000) != 0)
546	                    {
547	                        fprintf(stderr, "read_hex_file: number out of range in line %d\n", line_num);
548	                        fclose(file);
549	                        return NULL;
550	                    }
551	
552	                    number_value = (number_value << 4) | hex_digit_val(ch);
553	                }
554	                else
555	                {
556	                    append_to_segment(current_segment, number_value);
557	                    push_back_char = ch;
558	                    state = SCAN_SPACE;
559	                }
560	
561	                break;
562	
563	            case SCAN_ADDRESS:
564	                if (isxdigit(ch))
565	                    number_value = (number_value << 4) | hex_digit_val(ch);
566	                else
567	                {
568	                    push_back_char = ch;
569	                    state = SCAN_SPACE;
570	
571	                    // If there is no content in the current segment, reuse it. Otherwise
572	                    // create a new one.
573	                    if (current_segment->length > 0) {
574	                        current_segment->next = (struct segment*) calloc(sizeof(struct segment), 1);
575	                        current_segment = current_segment->next;
576	                    }
577	
578	                    current_segment->address = number_value * 4;
579	                }
580	
581	                break;
582	        }
583	    }
584	
585	    fclose(file);
586	
587	    return segments;
588	}
