590	bool read_binary_file(const char *filename, unsigned char **out_ptr, unsigned int *out_length)
591	{
592	    FILE *input_file;
593	    unsigned char *data;
594	    unsigned int file_length;
595	
596	    input_file = fopen(filename, "r");
597	    if (!input_file)
598	    {
599	        perror("Error opening input file");
600	        return false;
601	    }
602	
603	    fseek(input_file, 0, SEEK_END);
604	    file_length = (unsigned int) ftell(input_file);
605	    fseek(input_file, 0, SEEK_SET);
606	
607	    data = malloc(file_length);
608	    if (fread(data, file_length, 1, input_file) != 1)
609	    {
610	        perror("Error reading file");
611	        fclose(input_file);
612	        free(data);
613	        return false;
614	    }
615	
616	    *out_ptr = data;
617	    *out_length = file_length;
618	    fclose(input_file);
619	
620	    return true;
621	}
