623	void print_progress_bar(unsigned int current, unsigned int total)
624	{
625	    unsigned int num_ticks = current * PROGRESS_BAR_WIDTH / total;
626	    unsigned int i;
627	
628	    printf("\r_loading [");
629	    for (i = 0; i < num_ticks; i++)
630	        printf("=");
631	
632	    for (; i < PROGRESS_BAR_WIDTH; i++)
633	        printf(" ");
634	
635	    printf("] (%u%%)", current * 100 / total);
636	    fflush(stdout);
637	}
