639	static bool is_empty(unsigned char *data, unsigned int length)
640	{
641	    bool empty;
642	    unsigned int i;
643	
644	    empty = true;
645	    for (i = 0; i < length; i++)
646	    {
647	        if (data[i] != 0)
648	        {
649	            empty = false;
650	            break;
651	        }
652	    }
653	
654	    return empty;
655	}
656	
657	bool send_segment(int serial_fd, unsigned int address, unsigned char *data, unsigned int data_length)
658	{
659	    unsigned int offset = 0;
660	
661	    print_progress_bar(0, data_length);
662	    while (offset < data_length)
663	    {
664	        int copied_correctly = 1;
665	        unsigned int this_slice = data_length - offset;
666	        if (this_slice > BLOCK_SIZE)
667	            this_slice = BLOCK_SIZE;
668	
669	        if (is_empty(data + offset, this_slice))
670	        {
671	            if (!clear_memory(serial_fd, address + offset, this_slice))
672	                return false;
673	        }
674	        else
675	        {
676	            if (!load_memory(serial_fd, address + offset, data + offset, this_slice))
677	            {
678	                copied_correctly = 0;
679	                if (!fix_connection(serial_fd))
680	                {
681	                    return false;
682	                }
683	            }
684	        }
685	        if (copied_correctly)
686	        {
687	            offset += this_slice;
688	        }
689	        print_progress_bar(offset, data_length);
690	    }
691	
692	    return true;
693	}
694	
695	bool send_segments(int serial_fd, const struct segment *segments)
696	{
697	    const struct segment *current;
698	    for (current = segments; current; current = current->next) {
699	        if (!send_segment(serial_fd, current->address, current->data,
700	            current->length)) {
701	            return false;
702	        }
703	    }
704	
705	
706	    return true;
707	}
708	
709	int main(int argc, const char *argv[])
710	{
711	    struct segment *program_data;
712	    unsigned char *ramdisk_data = NULL;
713	    unsigned int ramdisk_length = 0;
714	    int serial_fd;
715	
716	    if (argc < 3)
717	    {
718	        fprintf(stderr, "USAGE:\n    serial_boot <serial port name> <hex file> [<ramdisk image>]\n");
719	        return 1;
720	    }
721	
722	    program_data = read_hex_file(argv[2]);
723	    if (program_data == NULL)
724	        return 1;
725	
726	    if (argc == 4)
727	    {
728	        // Load binary ramdisk image
729	        if (!read_binary_file(argv[3], &ramdisk_data, &ramdisk_length))
730	            return 1;
731	    }
732	
733	    serial_fd = open_serial_port(argv[1]);
734	    if (serial_fd < 0)
735	        return 1;
736	
737	    if (!ping_target(serial_fd))
738	        return 1;
739	
740	    if (!send_segments(serial_fd, program_data))
741	        return 1;
742	
743	    if (ramdisk_data)
744	    {
745	        printf("\n_ramdisk is %u bytes\n", ramdisk_length);
746	        if (!send_segment(serial_fd, RAMDISK_BASE, ramdisk_data, ramdisk_length))
747	            return 1;
748	    }
749	
750	    if (!send_execute_command(serial_fd))
751	        return 1;
752	
753	    printf("\n_program running, entering console mode\n");
754	
755	    do_console_mode(serial_fd);
756	
757	    return 0;
758	}
