#ifndef __PROTOCOL_H
#define __PROTOCOL_H

enum message_type
{
    LOAD_MEMORY_REQ = 0xc0,
    LOAD_MEMORY_ACK,
    EXECUTE_REQ,
    EXECUTE_ACK,
    PING_REQ,
    PING_ACK,
    CLEAR_MEMORY_REQ,
    CLEAR_MEMORY_ACK,
    BAD_COMMAND
};

#endif

