18	
19	//
20	// First stage serial bootloader. This communicates with a loader program on
21	// the host (tools/serial_boot), which loads a program into memory. Because
22	// this is running in ROM, it cannot use global variables.
23	//
24	
25	#define CLOCK_RATE 50000000
26	#define DEFAULT_UART_BAUD 921600
27	#define BLINK_DELAY 100000
28	
29	enum register_index
30	{
31	    REG_GREEN_LED = 0x04 / 4,
32	    REG_UART_STATUS = 0x40 / 4,
33	    REG_UART_RX = 0x44 / 4,
34	    REG_UART_TX = 0x48 / 4,
35	    REG_UART_DIVISOR = 0x4c / 4
36	};
37	
38	void *memset(void *_dest, int value, unsigned int length);
39	
40	static volatile unsigned int * const REGISTERS = (volatile unsigned int*) 0xffff0000;
41	
42	unsigned int read_serial_byte(void)
43	{
44	    int delay_counter = 0;
45	    int led_value = 0;
46	
47	    while ((REGISTERS[REG_UART_STATUS] & 2) == 0)
48	    {
49	        // Blink the LED while waiting to show signs of life.
50	        if (delay_counter++ > BLINK_DELAY)
51	        {
52	            delay_counter = 0;
53	            led_value = !led_value;
54	            REGISTERS[REG_GREEN_LED] = led_value;
55	        }
56	    }
57	
58	    return REGISTERS[REG_UART_RX];
59	}
60	
61	void write_serial_byte(unsigned int ch)
62	{
63	    while ((REGISTERS[REG_UART_STATUS] & 1) == 0)	// Wait for space
64	        ;
65	
66	    REGISTERS[REG_UART_TX] = ch;
67	}
68	
69	unsigned int read_serial_long(void)
70	{
71	    unsigned int result = 0;
72	    for (int i = 0; i < 4; i++)
73	        result = (result >> 8) | (read_serial_byte() << 24);
74	
75	    return result;
76	}
77	
78	void write_serial_long(unsigned int value)
79	{
80	    write_serial_byte(value & 0xff);
81	    write_serial_byte((value >> 8) & 0xff);
82	    write_serial_byte((value >> 16) & 0xff);
83	    write_serial_byte((value >> 24) & 0xff);
84	}
85	
86	int main()
87	{
88	    // Initialize UART speed
89	    REGISTERS[REG_UART_DIVISOR] = (CLOCK_RATE / DEFAULT_UART_BAUD) - 1;
90	
91	    for (;;)
92	    {
93	        // Read command type and dispatch
94	        switch (read_serial_byte())
95	        {
96	            case LOAD_MEMORY_REQ:
97	            {
98	                unsigned char *load_addr = (unsigned char*) read_serial_long();
99	                unsigned int length = read_serial_long();
100	                unsigned int checksum = 2166136261; // FNV-1a hash
101	                for (int i = 0; i < length; i++)
102	                {
103	                    unsigned int ch = read_serial_byte();
104	                    checksum = (checksum ^ ch) * 16777619;
105	                    *load_addr++ = ch;
106	                }
107	
108	                write_serial_byte(LOAD_MEMORY_ACK);
109	                write_serial_long(checksum);
110	                break;
111	            }
112	
113	            case CLEAR_MEMORY_REQ:
114	            {
115	                void *base_address = (void*) read_serial_long();
116	                unsigned int length = read_serial_long();
117	                memset(base_address, 0, length);
118	                write_serial_byte(CLEAR_MEMORY_ACK);
119	                break;
120	            }
121	
122	            case EXECUTE_REQ:
123	            {
124	                REGISTERS[REG_GREEN_LED] = 0;	// Turn off LED
125	                write_serial_byte(EXECUTE_ACK);
126	                return 0;	// Break out of main
127	            }
128	
129	            case PING_REQ:
130	                write_serial_byte(PING_ACK);
131	                break;
