    IO_UART,
    IO_SDCARD,
    IO_PS2,
    IO_VGA,
    IO_TIMER
} io_bus_source;
logic uart_rx_interrupt;
logic ps2_rx_interrupt;
logic virt_tdo;
logic virt_tck;
logic virt_tdi;
logic virt_data_reg;
/* verilator lint_off UNDRIVEN */
logic virt_reset;
