assign clk = clk50;

nyuzi #(.RESET_PC(BOOT_ROM_BASE)) nyuzi(
    .interrupt_req({11'd0,
        frame_interrupt,
        ps2_rx_interrupt,
        uart_rx_interrupt,
        timer_interrupt,
        1'b0}),
    .axi_bus(axi_bus_m[0]),
    .io_bus(nyuzi_io_bus),
    .jtag(jtag),
